import{WithParams}from"../primitives/WithParams.js";class Audio extends WithParams{constructor(){super(),this.audioContext=new AudioContext,this.inNode=this.context().createGain(),this.sampleCount=0,this.mirrorParams({gain:this.inNode.gain})}onblamready(){if(this.sourceElems=[...this.querySelectorAll("sample-blam, media-blam > audio, media-blam > video")],this.sourceElems.length<1)return console.log("< 1"),void this.fire("blamsources",{},this,!0);this.addEventListener("blamsource",this)}onblamsource(){this.sampleCount++,this.sourceElems.length==this.sampleCount&&(this.inNode.connect(this.context().destination),this.fire("blamsources",{},this))}static get observedAttributes(){return["gain"]}get gain(){let value=this.getAttribute("gain");return value?parseFloat(value):.75}set gain(value){this.setAttribute("gain",value)}get bpm(){let value=this.getAttribute("bpm");return value?parseFloat(value):120}set bpm(value){this.setAttribute("bpm",value)}}export{Audio};